<template>
  <div class="baseSetting">
    <el-form ref="ruleForm" :model="form" label-width="150px" class="demo-ruleForm">
      <el-form-item label="是否允許加盟商入駐">
        <el-radio-group v-model="form.status">
          <el-radio :label="true"> 允許 </el-radio>
          <el-radio :label="false"> 關閉 </el-radio>
        </el-radio-group>
      </el-form-item>
      <el-form-item v-if="form.settled_type" label="允許加盟商入駐類型">
        <el-checkbox-group v-model="form.settled_type">
          <el-checkbox label="enterprise"> 企業 </el-checkbox>
          <el-checkbox label="soletrader"> 個體戶 </el-checkbox>
        </el-checkbox-group>
      </el-form-item>
      <el-form-item label="商戶入駐連結（H5）">
        <span>{{ h5url }} </span>
        <a
          v-clipboard:copy="h5url"
          v-clipboard:success="onCopy"
          style="cursor: pointer; margin-left: 30px"
        >
          複製連結</a
        >
      </el-form-item>
      <div class="content">
        <p>入駐協議內容修改後，提交後對線上客戶生效。</p>
        <el-form-item label="入駐協議內容" label-width="100px">
          <SpRichText v-model="form.content" />
        </el-form-item>
      </div>
      <el-form-item style="text-align: center; margin-top: 30px" label-width="0">
        <el-button type="primary" @click="submitForm"> 儲存 </el-button>
      </el-form-item>
    </el-form>
  </div>
</template>

<script>
import { getShopConfig, saveShopConfig } from '@/api/mall/marketing.js'

export default {
  data() {
    return {
      form: {
        status: true,
        settled_type: [],
        content: ''
      },
      h5url: ''
    }
  },
  mounted() {
    this.getConfig()
  },
  methods: {
    async getConfig() {
      const result = await getShopConfig()
      this.form = result.data.data
      this.h5url = result.data.data.h5url
      delete this.form.h5url
    },
    updateContent(data) {
      this.form.content = data
    },
    async submitForm() {
      const result = await saveShopConfig(this.form)
      if (result.data.data.status) {
        this.$message.success('儲存成功')
        this.getConfig()
      }
    },
    onCopy() {
      this.$notify({
        message: '複製成功',
        type: 'success'
      })
    }
  }
}
</script>

